insert into public.memory_chunks (id, document_id, chunk_index, chunk_text, token_count, embedding_model, embedding, metadata) values ('6acd4c5c-f263-5597-8046-ac4eca999ad7', 'c767ffa5-ce1e-58b7-8548-7b9a5944d88e', 3, 'Expected shape:
- install `whisper-cli`
- install `ffmpeg` / `ffprobe`
- configure `tools.media.audio.models` with `type: cli`
- let OpenClaw transcode Telegram `.ogg` to `.wav` when needed

Complexity:
- medium

Price:
- near-zero API cost
- real cost is CPU/RAM/time on VPS

VPS load:
- medium to high depending on model and message volume
- likely the heaviest option here

Reliability:
- medium
- fewer external dependencies, but more operational sharp edges:
  - binary install
  - model file management
  - CPU spikes
  - slower inference
  - ffmpeg dependency

Privacy:
- high
- audio stays on your infrastructure

Rollback:
- remove CLI model config
- uninstall binaries later if desired
- revert to API provider or text-only mode

### Option C — intermediate webhook / microservice

Put a small STT service between Telegram/OpenClaw and the chosen transcription engine.

Two realistic sub-forms:
1. webhook service that accepts audio and returns transcript
2. OpenAI-compatible transcription endpoint wrapper so OpenClaw calls it like a provider

Use this if we need:
- custom retry logic
- queueing / rate limiting
- transcript normalization
- provider abstraction
- central audit / redaction / metrics
- reuse by multiple bots/channels later

Complexity:
- medium-high

Price:
- service maintenance cost + underlying STT provider cost
- cheapest if backed by Groq or local whisper; simplest if backed by OpenAI', 286, 'nomic-embed-text', '[-0.01203952,0.01969510,-0.16452813,-0.08502436,0.04563038,-0.08022645,-0.01533297,0.03525037,-0.04518421,-0.03460731,-0.03604634,0.02942021,-0.00684073,0.06722174,0.01589520,-0.01417839,0.00618444,-0.02048050,-0.00107662,0.00548799,-0.02682658,-0.07141378,-0.01564200,-0.04248753,0.05218641,0.00816887,0.00019714,0.04509990,-0.05114124,0.02778206,0.04619689,-0.06767815,-0.01412489,0.00001226,-0.08815858,-0.04877864,-0.00248186,-0.00046972,-0.01579674,0.07792380,0.06036057,-0.04936758,0.00642219,-0.02563287,0.06006129,-0.02108248,0.04103037,0.03433862,0.04798429,-0.11789752,0.04000704,0.01323542,-0.01109756,0.02160089,0.10679422,-0.00267306,-0.01469696,0.03958713,-0.02022712,-0.02901804,0.01399176,0.08701033,-0.09178899,0.05327004,0.00680965,0.02879032,-0.02319198,0.00283141,0.03690388,-0.03434882,0.02792919,-0.00573287,-0.01163155,-0.00583626,-0.00299907,-0.01199430,-0.04630087,-0.08240625,-0.00599773,0.00596786,0.02489424,-0.00910872,0.05177339,-0.02318973,0.02285182,-0.02591242,-0.00328322,0.03016874,-0.01311037,0.05034111,-0.03956640,-0.02935755,0.00864002,0.03345424,-0.05073097,0.00217281,-0.03618271,0.05261151,0.02622856,-0.04129863,-0.01672983,0.00610918,0.00841535,-0.02182505,0.01030060,0.02163802,-0.00556956,0.03762608,0.00779472,-0.00461518,0.00765357,0.05472333,0.02810906,-0.01439435,-0.01725815,-0.09124795,0.04430409,0.02630117,0.00728816,0.08307008,0.00440239,-0.05988590,0.00029346,0.02166296,0.01760368,0.03903961,-0.05587283,0.03401381,-0.00657257,-0.02529640,-0.01195446,0.01197414,-0.03612921,0.00588473,0.02083483,0.07587942,-0.07987250,-0.02691739,0.00411778,0.00417166,0.01378251,0.04612527,0.02645682,-0.03651074,-0.05460903,-0.01725043,-0.02602988,-0.03810815,-0.00287961,0.01215830,0.01159527,0.00161150,0.01137293,0.03203900,0.01340146,-0.01035657,0.03336540,0.01194475,0.01638473,0.05893913,0.00539763,-0.00152528,-0.04216749,0.06604050,-0.00496065,-